// Quellen für den KI-Wochenrückblick aufbereiten (aus EINER breiten Suche).
// Tavily-Ergebnisse ROBUST einlesen - egal wie n8n die HTTP-Antwort strukturiert.
function fromObj(o) {
  if (!o || typeof o !== 'object') return null;
  if (Array.isArray(o.results)) return o.results;
  if (o.body && Array.isArray(o.body.results)) return o.body.results;
  if (o.data && Array.isArray(o.data.results)) return o.data.results;
  return null;
}
function scan(items) {
  if (!Array.isArray(items)) return null;
  // a) ein Item enthält die results-Liste (Standardfall)
  for (const it of items) {
    const j = (it && it.json) ? it.json : it;
    const r = fromObj(j);
    if (r && r.length) return r;
  }
  // b) Items SIND die Ergebnisse (gesplittet -> jedes hat url)
  const hits = items.map(it => (it && it.json) ? it.json : it).filter(x => x && x.url);
  if (hits.length) return hits;
  return null;
}
// Bewusst nur .all() (manche n8n-Versionen liefern .first() unerwartet).
let results = [];
try { results = scan($input.all()) || results; } catch (e) {}
if (!results.length) { try { results = scan($('Themen-Recherche (Tavily)').all()) || results; } catch (e) {} }
if (!results.length) { try { if (Array.isArray($json.results)) results = $json.results; } catch (e) {} }

// Eingebaute Diagnose (zeigt im Output, was wirklich am Eingang lag)
let _debug = null;
try {
  const a = $input.all();
  const j0 = (a[0] && a[0].json) ? a[0].json : null;
  _debug = {
    input_items: a.length,
    first_keys: j0 ? Object.keys(j0) : [],
    results_is_array: !!(j0 && Array.isArray(j0.results)),
    results_len: (j0 && Array.isArray(j0.results)) ? j0.results.length : -1
  };
} catch (e) { _debug = { err: String(e) }; }

// Domain aus URL extrahieren
const domainOf = (url) => {
  try { return new URL(url).hostname.replace(/^www\./, ''); }
  catch (e) { return ''; }
};

// Nach Tavily-Relevanz sortieren, je Domain nur die beste Meldung, max. 7 Quellen
results = results.slice().sort((a, b) => (b.score || 0) - (a.score || 0));
const seenDomains = new Set();
const sources = [];
for (const r of results) {
  if (!r.url) continue;
  const d = domainOf(r.url);
  if (!d || seenDomains.has(d)) continue;
  seenDomains.add(d);
  const content = (r.content || r.raw_content || '')
    .replace(/\s+/g, ' ').trim().substring(0, 1500);
  sources.push({
    url: r.url,
    title: r.title || '',
    published_date: r.published_date || '',
    domain: d,
    snippet: content
  });
  if (sources.length >= 7) break;
}

// Mindestens 3 verschiedene Domains erforderlich (Anti-Halluzination)
const enough_sources = sources.length >= 3;

// Exakter System-Prompt
const claude_system = "Du bist Redakteur für den AK-Assistance-Blog. Zielgruppe: deutsche Handwerksbetriebe,\ndie wissen wollen, was in der KI-Welt passiert und was es für sie bedeutet.\n\nDu erhältst eine Liste echter, aktueller Nachrichtenquellen zur KI-Welt. Erstelle daraus\neinen redaktionellen Wochenrückblick.\n\nStrikte Regeln:\n- Verwende AUSSCHLIESSLICH die unten gelieferten Quellen. Keine Information, die dort nicht\n  steht, darf in den Artikel. Keine Zahlen, Zitate, Studien oder Personen erfinden.\n- Wähle die 3–5 wichtigsten, für Handwerksbetriebe relevantesten Meldungen aus. Lass\n  themenfremde oder belanglose Einträge weg.\n- Ordne jede Meldung kurz ein: Was bedeutet das (falls relevant) für Handwerksbetriebe?\n- Wenn eine Quelle unklar oder widersprüchlich ist, benenne das.\n- Schreibe auf Deutsch, sachlich, klar, ohne Marketing-Floskeln.\n- Länge: 600–900 Wörter.\n- Struktur: H1-Titel, kurze Einleitung (2–3 Sätze), 3–5 H2-Abschnitte (je eine Meldung),\n  Fazit, Quellenliste.\n- Quellenliste am Ende als nummerierte Liste: [Nr] Titel — Domain (Datum) — URL.\n- Verwende nur Quellen, die du auch wirklich im Text verarbeitet hast.\n- Wenn weniger als 3 verwertbare Quellen vorhanden sind, antworte ausschließlich mit:\n  \"INSUFFICIENT_SOURCES\".\n\nGib das Ergebnis als JSON zurück:\n{\n  \"title\": \"...\",\n  \"slug\": \"...\",\n  \"meta_description\": \"... (max 155 Zeichen, SEO-tauglich)\",\n  \"keywords\": [\"...\", \"...\"],\n  \"body_markdown\": \"...\",\n  \"sources_used\": [{\"url\": \"...\", \"title\": \"...\", \"date\": \"...\"}]\n}";

// User-Message: alle aufbereiteten Quellen (Titel, Domain, Datum, URL, Inhalt)
const quellenText = sources.map((s, i) =>
  `[${i + 1}] ${s.title}\nDomain: ${s.domain}\nDatum: ${s.published_date || 'unbekannt'}\nURL: ${s.url}\nInhalt: ${s.snippet}`
).join('\n\n');

let heute = '';
try { heute = $now.toFormat('dd.MM.yyyy'); } catch (e) { heute = new Date().toLocaleDateString('de-DE'); }
const claude_user = `Erstelle einen KI-Wochenrückblick (Stand ${heute}) aus diesen Quellen:\n\n${quellenText}`;

return [{ json: {
  enough_sources,
  sources_count: sources.length,
  domains_count: seenDomains.size,
  _debug,
  sources,
  claude_system,
  claude_user
}}];

// Claude-Antwort parsen und auf Verwertbarkeit prüfen.
const resp = $input.first().json;
const text = (resp.content && resp.content[0] && resp.content[0].text) ? resp.content[0].text : '';

// Anti-Halluzination: zu wenige Quellen -> klares Abbruchsignal
if (text.trim().includes('INSUFFICIENT_SOURCES')) {
  return [{ json: { article_valid: false, reason: 'INSUFFICIENT_SOURCES' } }];
}

// JSON aus der Antwort extrahieren (robust gegen umschließenden Text)
let parsed = null;
try {
  parsed = JSON.parse(text.trim());
} catch (e) {
  const m = text.match(/\{[\s\S]*\}/);
  if (m) { try { parsed = JSON.parse(m[0]); } catch (e2) {} }
}

// Pflichtfelder müssen vorhanden sein, sonst gilt der Artikel als ungültig
if (!parsed || !parsed.title || !parsed.body_markdown) {
  return [{ json: { article_valid: false, reason: 'PARSE_ERROR' } }];
}

// Slug absichern (falls Claude keinen liefert)
const slug = parsed.slug || parsed.title.toLowerCase()
  .replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');

return [{ json: {
  article_valid: true,
  title: parsed.title,
  slug,
  meta_description: parsed.meta_description || '',
  keywords: Array.isArray(parsed.keywords) ? parsed.keywords : [],
  body_markdown: parsed.body_markdown,
  sources_used: Array.isArray(parsed.sources_used) ? parsed.sources_used : []
}}];

